{
  "command": "sqlite3 '/workspace/DataAgentBench/query_PATENTS/query_dataset/patent_publication.db' \"SELECT filing_date FROM publicationinfo LIMIT 30\"",
  "description": "Sample filing dates"
}

{
  "command": "psql -h 127.0.0.1 -U user -d patent_CPCDefinition -c \"SELECT level, COUNT(*) FROM cpc_definition GROUP BY level ORDER BY level\"",
  "description": "Levels in CPC"
}

{
  "command": "psql -h 127.0.0.1 -U user -d patent_CPCDefinition -c \"SELECT symbol, level, titlePart FROM cpc_definition WHERE level = 5 LIMIT 20\"",
  "description": "Sample level 5 CPC"
}

{
  "command": "psql -h 127.0.0.1 -U user -d patent_CPCDefinition -c \"SELECT symbol, level, \\\"titlePart\\\" FROM cpc_definition WHERE level = 5 LIMIT 20\"",
  "description": "Sample level 5 CPC"
}

{
  "command": "psql -h 127.0.0.1 -U user -d patent_CPCDefinition -c \"SELECT LENGTH(symbol) as len, COUNT(*) FROM cpc_definition WHERE level = 5 GROUP BY LENGTH(symbol)\"",
  "description": "Check level 5 code length"
}

{
  "command": "sqlite3 '/workspace/DataAgentBench/query_PATENTS/query_dataset/patent_publication.db' \"SELECT DISTINCT filing_date FROM publicationinfo LIMIT 200\"",
  "description": "distinct date formats"
}

{
  "command": "psql -h 127.0.0.1 -U user -d patent_CPCDefinition -tA -c \"SELECT symbol FROM cpc_definition WHERE level = 5\" > /tmp/level5_symbols.txt\nwc -l /tmp/level5_symbols.txt",
  "description": "Dump level-5 symbols"
}
